SELECT 
FROM carbon_record
WHERE user_id = #{userId}

    AND activity_type = #{query.activityType}


    AND sub_type = #{query.subType}


    AND occurred_at >= #{query.startDate}


    AND occurred_at < DATE_ADD(#{query.endDate}, INTERVAL 1 DAY)

ORDER BY occurred_at DESC, id DESC

SELECT COALESCE(SUM(emission_kg), 0)
FROM carbon_record
WHERE user_id = #{userId}

SELECT COALESCE(SUM(emission_kg), 0)
FROM carbon_record
WHERE user_id = #{userId}
  AND occurred_at >= #{startTime}

SELECT COALESCE(SUM(emission_kg), 0)
FROM carbon_record
WHERE user_id = #{userId}
  AND activity_type = #{activityType}
  AND occurred_at >= #{startTime}

SELECT COUNT(1)
FROM carbon_record
WHERE user_id = #{userId}

SELECT DATE_FORMAT(occurred_at, '%Y-%m-%d') AS date,
       ROUND(SUM(emission_kg), 2) AS emissionKg
FROM carbon_record
WHERE user_id = #{userId}
  AND occurred_at >= #{startTime}
  AND occurred_at < #{endTime}
GROUP BY DATE_FORMAT(occurred_at, '%Y-%m-%d')
ORDER BY date ASC
